  return (
    <div className='sidebar'>
        {/* Icon */}
            <XIcon className='sidebar__xIcon'/>
        {/* Sidebar Option */}
            <SidebarOption text="ホーム" Icon={HomeIcon}/>
            <SidebarOption text="" Icon={HomeIcon}/>
            <SidebarOption text="ホーム" Icon={HomeIcon}/>
            <SidebarOption text="ホーム" Icon={HomeIcon}/>
            <SidebarOption text="ホーム" Icon={HomeIcon}/>
            <SidebarOption text="ホーム" Icon={HomeIcon}/>
            <SidebarOption text="ホーム" Icon={HomeIcon}/>
            <SidebarOption text="ホーム" Icon={HomeIcon}/>
        {/* Tweet Button */}
    </div>
  )
}

export default Sidebar;
